import pandas as pd
import math

# 使用上游已汇总的区县排放聚合结果，不重新查询或重新解析实体
sr_agg_exhaust_df = da_exhaust_agg_by_district_df.copy()

if "district_id" not in sr_agg_exhaust_df.columns:
    if sr_agg_exhaust_df.index.name == "district_id":
        sr_agg_exhaust_df = sr_agg_exhaust_df.reset_index()
    else:
        raise ValueError("上游聚合结果中缺少 district_id，无法按指定区县赋值。")

sr_exhaust_candidate_cols = [
    "total_exhaust", "total_exhaust_gas", "sum_exhaust_gas", "exhaust_gas_sum",
    "total_exhaust_gas_volume", "exhaust_gas"
]
sr_exhaust_col = next((c for c in sr_exhaust_candidate_cols if c in sr_agg_exhaust_df.columns), None)
if sr_exhaust_col is None:
    sr_numeric_cols = [
        c for c in sr_agg_exhaust_df.columns
        if c != "district_id" and pd.api.types.is_numeric_dtype(sr_agg_exhaust_df[c])
    ]
    sr_exhaust_like_cols = [c for c in sr_numeric_cols if "exhaust" in c.lower()]
    if sr_exhaust_like_cols:
        sr_exhaust_col = sr_exhaust_like_cols[0]
    elif len(sr_numeric_cols) == 1:
        sr_exhaust_col = sr_numeric_cols[0]
    else:
        raise ValueError(f"无法在上游聚合结果中唯一识别 exhaust_gas 汇总列；可用列：{list(sr_agg_exhaust_df.columns)}")

sr_totals_by_district = (
    sr_agg_exhaust_df[["district_id", sr_exhaust_col]]
    .assign(district_id=lambda x: x["district_id"].astype(int),
            _exhaust_total=lambda x: pd.to_numeric(x[sr_exhaust_col], errors="coerce"))
    .groupby("district_id", as_index=True)["_exhaust_total"]
    .sum(min_count=1)
)

if len(da_missing_expected_emission_ids) > 0:
    raise ValueError(f"上游标记存在预期但缺失排放数据的区县ID：{da_missing_expected_emission_ids}")

if da_district_id_changan not in sr_totals_by_district.index or da_district_id_jingxing_mining not in sr_totals_by_district.index:
    raise ValueError("上游聚合结果未包含两个目标区县的完整排放汇总。")

sr_changan_total = sr_totals_by_district.loc[da_district_id_changan]
sr_jingxing_total = sr_totals_by_district.loc[da_district_id_jingxing_mining]

if pd.isna(sr_changan_total) or pd.isna(sr_jingxing_total):
    raise ValueError("目标区县排放汇总存在空值，无法计算。")
if float(sr_changan_total) <= 0 or float(sr_jingxing_total) <= 0:
    raise ValueError("目标区县排放汇总为零或负值，按任务要求不静默存储零值。")

total_exhaust_changan = float(sr_changan_total)
total_exhaust_jingxing = float(sr_jingxing_total)

if total_exhaust_changan > total_exhaust_jingxing:
    higher_emission_district_id = int(da_district_id_changan)
    sr_higher_total = total_exhaust_changan
    sr_lower_total = total_exhaust_jingxing
elif total_exhaust_jingxing > total_exhaust_changan:
    higher_emission_district_id = int(da_district_id_jingxing_mining)
    sr_higher_total = total_exhaust_jingxing
    sr_lower_total = total_exhaust_changan
else:
    raise ValueError("两个区县排放总量相等，无法确定唯一的 higher_emission_district_id。")

emission_ratio = float(round(sr_higher_total / sr_lower_total, 2))

print("total_exhaust_changan =", total_exhaust_changan)
print("total_exhaust_jingxing =", total_exhaust_jingxing)
print("higher_emission_district_id =", higher_emission_district_id)
print("emission_ratio =", emission_ratio)
